-- Replace template_content with properly structured HTML for the 6 affected legal docs.
-- Generated from the Markdown in src/constants/{cpaDefaults,legalDefaults}.constants.ts
-- via the same markdownToHtml() the editor uses, so source and DB stay in sync.

DO $repair$
DECLARE
  c_quick text := E'<h1>Challenge Participation Agreement — Quick Mode</h1>\n<h2>1. Parties</h2>\n<p>This Agreement is entered into between the Challenge Seeker organization (the <strong>"Seeker"</strong>) and the participating Solution Provider (the <strong>"Solution Provider"</strong>) on the platform operated by <strong>{{platform_name}}</strong> (the <strong>"Platform"</strong>).</p>\n<h2>2. Challenge Details</h2>\n<ul><li><strong>Challenge Title:</strong> {{challenge_title}}</li><li><strong>Governance Mode:</strong> Quick</li><li><strong>Total Prize:</strong> {{total_fee}} {{currency}}</li><li><strong>Submission Deadline:</strong> {{submission_deadline}}</li></ul>\n<h2>3. Scope of Work</h2>\n<p>{{scope}}</p>\n<h2>4. Intellectual Property</h2>\n<p>{{ip_model}}</p>\n<p>The IP terms above govern any deliverable produced under this challenge.</p>\n<h2>5. Confidentiality</h2>\n<p>Both parties agree to keep all non-public challenge materials, submissions and evaluation data confidential, both during the challenge and for <strong>2 years</strong> after its conclusion.</p>\n<h2>6. Payment</h2>\n<p>Prize funds are held in escrow by the Platform and released to the winning Solution Provider upon confirmation by the Seeker.</p>\n<h2>7. Governing Law</h2>\n<p>This Agreement is governed by <strong>{{governing_law}}</strong> with exclusive jurisdiction in <strong>{{jurisdiction}}</strong>.</p>\n<h2>8. Acceptance</h2>\n<p>By clicking <strong>Accept</strong>, the Solution Provider confirms they have read, understood and agree to be bound by the terms of this Agreement.</p>';

  c_struct text := E'<h1>Challenge Participation Agreement — Structured Mode</h1>\n<h2>1. Parties</h2>\n<p>This Challenge Participation Agreement (the <strong>"Agreement"</strong>) is entered into between the Challenge Seeker organization (the <strong>"Seeker"</strong>) and the participating Solution Provider (the <strong>"Solution Provider"</strong>), each a <strong>"Party"</strong> and collectively the <strong>"Parties"</strong>, on the platform operated by <strong>{{platform_name}}</strong> (the <strong>"Platform"</strong>).</p>\n<h2>2. Challenge Details</h2>\n<ul><li><strong>Challenge Title:</strong> {{challenge_title}}</li><li><strong>Governance Mode:</strong> {{governance_mode}}</li><li><strong>Prize Pool:</strong> {{total_fee}} {{currency}}</li><li><strong>Submission Deadline:</strong> {{submission_deadline}}</li></ul>\n<h2>3. Problem Statement</h2>\n<p>{{problem_statement}}</p>\n<h2>4. Scope of Work</h2>\n<p>{{scope}}</p>\n<p>The Solution Provider shall deliver work products that meet the requirements set out above and any acceptance criteria published by the Seeker.</p>\n<h2>5. Intellectual Property</h2>\n<p>{{ip_model}}</p>\n<p>All intellectual property created during the challenge shall be governed by the model specified above. Pre-existing IP of either Party remains the property of that Party.</p>\n<h2>6. Escrow and Payment</h2>\n<ul><li>The total prize pool is deposited in escrow by the Seeker prior to publication.</li><li>Escrow funds are released to the winning Solution Provider on Seeker''s written confirmation of acceptance.</li><li>Platform fees, if any, are deducted by the Platform in accordance with the published rate card.</li></ul>\n<h2>7. Confidentiality</h2>\n<p>The Parties shall maintain in strict confidence all non-public materials shared during the challenge, including the brief, submissions, evaluation scores and reviewer identities. Confidentiality obligations survive termination for <strong>3 years</strong>.</p>\n<h2>8. Evaluation</h2>\n<p>Submissions shall be evaluated using the criteria published in the challenge brief. Decisions of the Seeker, supported by the Platform''s evaluation framework, are final.</p>\n<h2>9. Termination</h2>\n<p>Either Party may withdraw from the challenge prior to the submission deadline subject to the rules published on the Platform. Withdrawal does not relieve the Solution Provider of confidentiality obligations.</p>\n<h2>10. Governing Law and Jurisdiction</h2>\n<p>This Agreement is governed by <strong>{{governing_law}}</strong> with exclusive jurisdiction in <strong>{{jurisdiction}}</strong>.</p>\n<h2>11. Acceptance</h2>\n<p>By clicking <strong>Accept</strong>, the Solution Provider confirms they have read, understood and agree to be bound by this Agreement.</p>';

  c_ctrl text := E'<h1>Challenge Participation Agreement — Controlled Mode</h1>\n<h2>1. Definitions and Parties</h2>\n<p>This Challenge Participation Agreement (the <strong>"Agreement"</strong>) is entered into by and between the Challenge Seeker organization (the <strong>"Seeker"</strong>) and the participating Solution Provider (the <strong>"Solution Provider"</strong>), each a <strong>"Party"</strong> and collectively the <strong>"Parties"</strong>, on the platform operated by <strong>{{platform_name}}</strong> (the <strong>"Platform"</strong>).</p>\n<h2>2. Challenge Specification</h2>\n<ul><li><strong>Challenge Title:</strong> {{challenge_title}}</li><li><strong>Governance Mode:</strong> {{governance_mode}}</li><li><strong>Total Prize Pool:</strong> {{total_fee}} {{currency}}</li><li><strong>Submission Deadline:</strong> {{submission_deadline}}</li></ul>\n<h2>3. Problem Statement</h2>\n<p>{{problem_statement}}</p>\n<h2>4. Scope and Deliverables</h2>\n<p>{{scope}}</p>\n<p>The Solution Provider shall deliver work products that meet the requirements above and any documented acceptance criteria.</p>\n<h2>5. Intellectual Property Assignment</h2>\n<p>{{ip_model}}</p>\n<h3>5.1 Pre-existing IP</h3>\n<p>The Solution Provider retains all pre-existing intellectual property used in the course of the challenge.</p>\n<h3>5.2 Challenge-Created IP</h3>\n<p>Intellectual property created specifically for this challenge transfers in accordance with the model above upon Seeker''s acceptance and full payment.</p>\n<h3>5.3 Moral Rights</h3>\n<p>To the extent permitted by law, the Solution Provider waives any moral rights in challenge-created IP in favour of the Seeker.</p>\n<h2>6. Anti-Disintermediation</h2>\n<p>For a period of <strong>24 months</strong> following the close of the challenge, neither Party shall engage in direct commercial relationships with the other (or with their respective affiliates introduced via the Platform) bypassing the Platform, except with the Platform''s prior written consent.</p>\n<h2>7. Escrow and Payment Terms</h2>\n<ul><li>The total prize pool is deposited in escrow prior to publication.</li><li>Escrow funds are released to the winning Solution Provider only on Seeker''s written confirmation of acceptance, subject to the dispute-resolution clause below.</li><li>Platform fees are deducted in accordance with the published rate card.</li></ul>\n<h2>8. Confidentiality and Data Protection</h2>\n<ul><li>All challenge materials are confidential.</li><li>Personal data is processed in accordance with applicable data-protection law (including GDPR where relevant) and the Platform''s Data Processing Agreement (DPA).</li><li>Confidentiality obligations survive termination for <strong>5 years</strong>.</li></ul>\n<h2>9. Warranties and Indemnities</h2>\n<p>Each Party warrants that it has the authority to enter into this Agreement. The Solution Provider warrants that the deliverables will not infringe any third-party rights and shall indemnify the Seeker against any claim to the contrary.</p>\n<h2>10. Dispute Resolution</h2>\n<p>Any dispute arising out of or in connection with this Agreement shall be resolved through binding arbitration administered by the institution and seat specified by <strong>{{governing_law}}</strong>.</p>\n<h2>11. Jurisdiction and Governing Law</h2>\n<ul><li><strong>Jurisdiction:</strong> {{jurisdiction}}</li><li><strong>Governing Law:</strong> {{governing_law}}</li></ul>\n<h2>12. Termination</h2>\n<p>Either Party may terminate participation by giving <strong>30 days</strong> written notice via the Platform. Termination does not affect rights or obligations accrued prior to termination, nor surviving clauses (Confidentiality, IP, Anti-Disintermediation).</p>\n<h2>13. General Provisions</h2>\n<p>This Agreement, together with the documents referenced herein, constitutes the entire agreement between the Parties in respect of its subject matter and supersedes all prior negotiations and understandings.</p>\n<h2>14. Acceptance</h2>\n<p>By clicking <strong>Accept</strong>, the Solution Provider confirms they have read, understood and agree to be bound by this Agreement.</p>';

  c_ra text := E'<h1>Seeker Organization Admin — Role Agreement (RA_R2)</h1>\n<h2>1. Parties</h2>\n<p>This Role Agreement is entered into between <strong>{{platform_name}}</strong> (the <strong>"Platform"</strong>) and the individual being granted the Seeker Organization Admin role (the <strong>"Admin"</strong>) on behalf of <strong>{{organization_name}}</strong> (the <strong>"Organization"</strong>).</p>\n<h2>2. Scope of Role</h2>\n<p>The Admin is authorised to manage the Organization''s presence on the Platform, including:</p>\n<ul><li>Inviting, granting and revoking workforce roles (Creator, Curator, Reviewer, Finance Coordinator, Legal Coordinator).</li><li>Configuring challenges, governance modes and legal documents on behalf of the Organization.</li><li>Approving budgets, escrow deposits and prize payouts within delegated limits.</li><li>Acting as the primary point of contact between the Organization and the Platform for compliance and escalations.</li></ul>\n<h2>3. Relationship to SKPA</h2>\n<p>This Agreement is <strong>personal</strong> to the Admin and is in addition to the Seeker Platform Agreement (SKPA) signed by the Organization. The SKPA governs the Organization''s commercial relationship with the Platform; this Role Agreement governs the Admin''s individual conduct, authority and obligations.</p>\n<h2>4. Confidentiality</h2>\n<p>The Admin shall keep confidential all non-public information accessed via the Platform, including challenge briefs, Solution Provider submissions, evaluation scores and financial records. Confidentiality obligations survive termination of the role for <strong>3 years</strong>.</p>\n<h2>5. Acceptable Use</h2>\n<p>The Admin shall not:</p>\n<ul><li>Share login credentials or platform access with unauthorised persons.</li><li>Use Platform data for purposes outside the Organization''s challenge programme.</li><li>Attempt to circumvent governance, escrow or evaluation controls.</li><li>Engage in any activity that would breach the Platform''s Acceptable Use Policy.</li></ul>\n<h2>6. Data Protection</h2>\n<p>The Admin shall handle personal data in accordance with applicable data-protection law (including GDPR where relevant) and the Platform''s Data Processing Agreement (DPA).</p>\n<h2>7. Termination</h2>\n<p>This Agreement terminates automatically when the Admin''s role is revoked by the Organization or by the Platform. Confidentiality and data-protection obligations survive termination.</p>\n<h2>8. Governing Law</h2>\n<p>This Agreement is governed by <strong>{{governing_law}}</strong> with exclusive jurisdiction in <strong>{{jurisdiction}}</strong>.</p>\n<h2>9. Acceptance</h2>\n<p>By clicking <strong>Accept</strong>, the Admin confirms they have read, understood and agree to be bound by this Role Agreement.</p>';

  c_pp text := E'<h1>Privacy Policy</h1>\n<p><em>Last updated: {{effective_date}}</em></p>\n<h2>1. Introduction</h2>\n<p><strong>{{platform_name}}</strong> (the <strong>"Platform"</strong>, <strong>"we"</strong>, <strong>"us"</strong>) respects your privacy. This Privacy Policy explains what personal data we collect, how we use it, the legal basis for processing, and your rights as a data subject.</p>\n<h2>2. Data Controller</h2>\n<p>The data controller for personal data processed via the Platform is <strong>{{platform_name}}</strong>. Contact: <strong>privacy@{{platform_domain}}</strong>.</p>\n<h2>3. Categories of Personal Data We Collect</h2>\n<ul><li><strong>Identity data:</strong> name, job title, organization.</li><li><strong>Contact data:</strong> email address, phone number, business address.</li><li><strong>Account data:</strong> username, hashed password, role assignments, preferences.</li><li><strong>Usage data:</strong> logins, page views, actions performed on the Platform.</li><li><strong>Submission data:</strong> content you upload as part of challenges, applications or proposals.</li><li><strong>Technical data:</strong> IP address, browser type, device identifiers, cookies.</li></ul>\n<h2>4. How We Use Personal Data (Lawful Basis)</h2>\n<table><thead><tr><th>Purpose</th><th>Lawful basis</th></tr></thead><tbody><tr><td>Operating the Platform and providing requested services</td><td>Contract</td></tr><tr><td>Account security, fraud prevention and audit logging</td><td>Legitimate interest</td></tr><tr><td>Sending transactional notifications</td><td>Contract</td></tr><tr><td>Sending marketing communications</td><td>Consent</td></tr><tr><td>Compliance with legal obligations</td><td>Legal obligation</td></tr></tbody></table>\n<h2>5. Sharing and Disclosure</h2>\n<p>We share personal data only with:</p>\n<ul><li><strong>Other users</strong> of the Platform, to the extent required for the challenge or workflow you participate in.</li><li><strong>Sub-processors</strong> (hosting, email, analytics, payment) under written data-processing agreements.</li><li><strong>Authorities</strong> where required by law or court order.</li></ul>\n<p>We do <strong>not</strong> sell personal data.</p>\n<h2>6. International Transfers</h2>\n<p>Where personal data is transferred outside the EEA / UK, we rely on Standard Contractual Clauses or other lawful transfer mechanisms.</p>\n<h2>7. Retention</h2>\n<ul><li>Account data is retained for the lifetime of your account plus <strong>24 months</strong>.</li><li>Audit logs and legal-acceptance ledger entries are retained for <strong>7 years</strong>.</li><li>Marketing data is retained until you withdraw consent.</li></ul>\n<h2>8. Your Rights</h2>\n<p>You have the right to:</p>\n<ul><li>Access the personal data we hold about you.</li><li>Request correction of inaccurate data.</li><li>Request erasure (right to be forgotten), subject to legal retention obligations.</li><li>Object to or restrict processing.</li><li>Data portability.</li><li>Withdraw consent at any time.</li><li>Lodge a complaint with your local supervisory authority.</li></ul>\n<p>To exercise these rights contact <strong>privacy@{{platform_domain}}</strong>.</p>\n<h2>9. Cookies</h2>\n<p>The Platform uses essential cookies for authentication and session management, and optional cookies for analytics. See our Cookie Notice for details and to manage preferences.</p>\n<h2>10. Security</h2>\n<p>We implement appropriate technical and organisational measures, including encryption in transit, access controls, audit logging and regular security reviews.</p>\n<h2>11. Changes to this Policy</h2>\n<p>We may update this Policy from time to time. Material changes will be notified in-Platform and by email where appropriate.</p>\n<h2>12. Governing Law</h2>\n<p>This Policy is governed by <strong>{{governing_law}}</strong> with exclusive jurisdiction in <strong>{{jurisdiction}}</strong>.</p>';

  c_dpa text := E'<h1>Data Processing Agreement (DPA)</h1>\n<p><em>Last updated: {{effective_date}}</em></p>\n<h2>1. Parties</h2>\n<p>This Data Processing Agreement (the <strong>"DPA"</strong>) is entered into between the customer organization (the <strong>"Controller"</strong>) and <strong>{{platform_name}}</strong> (the <strong>"Processor"</strong>) and forms part of the agreement under which the Processor provides services to the Controller (the <strong>"Principal Agreement"</strong>).</p>\n<h2>2. Definitions</h2>\n<p>Terms such as <strong>"Personal Data"</strong>, <strong>"Processing"</strong>, <strong>"Data Subject"</strong>, <strong>"Sub-processor"</strong> and <strong>"Supervisory Authority"</strong> have the meanings given in the General Data Protection Regulation (GDPR) and equivalent applicable data-protection law.</p>\n<h2>3. Subject Matter and Duration</h2>\n<ul><li><strong>Subject matter:</strong> Processing of Personal Data by the Processor on behalf of the Controller in connection with the Platform services.</li><li><strong>Duration:</strong> For the term of the Principal Agreement, plus the retention periods set out below.</li></ul>\n<h2>4. Nature and Purpose of Processing</h2>\n<p>The Processor will process Personal Data for the purpose of providing, operating, securing and supporting the Platform services as described in the Principal Agreement.</p>\n<h2>5. Categories of Data Subjects and Personal Data</h2>\n<ul><li><strong>Data Subjects:</strong> Controller''s users, employees, contractors, challenge participants and contacts.</li><li><strong>Personal Data:</strong> Identity, contact, account, usage, submission and technical data as described in the Privacy Policy.</li></ul>\n<h2>6. Obligations of the Processor</h2>\n<p>The Processor shall:</p>\n<ul><li>Process Personal Data only on documented instructions from the Controller.</li><li>Ensure persons authorised to process Personal Data are bound by confidentiality.</li><li>Implement appropriate technical and organisational security measures (Annex A).</li><li>Assist the Controller in responding to Data Subject requests.</li><li>Notify the Controller of a Personal Data Breach without undue delay (and in any event within <strong>72 hours</strong> of becoming aware).</li><li>Make available all information necessary to demonstrate compliance and contribute to audits.</li></ul>\n<h2>7. Sub-processors</h2>\n<ul><li>The Controller authorises the Processor to engage Sub-processors listed in Annex B.</li><li>The Processor will give the Controller prior notice of any intended changes and the Controller may object on reasonable grounds.</li><li>The Processor remains liable for the acts and omissions of its Sub-processors.</li></ul>\n<h2>8. International Transfers</h2>\n<p>Where Personal Data is transferred outside the EEA / UK, the Processor relies on Standard Contractual Clauses or other lawful transfer mechanisms.</p>\n<h2>9. Security Measures (Annex A)</h2>\n<ul><li>Encryption of Personal Data in transit (TLS 1.2+) and at rest.</li><li>Role-based access control with least-privilege principle.</li><li>Audit logging of administrative and security-relevant events.</li><li>Regular vulnerability scanning and penetration testing.</li><li>Documented incident-response and business-continuity procedures.</li><li>Background checks for personnel with access to Personal Data.</li></ul>\n<h2>10. Data Subject Rights</h2>\n<p>The Processor shall, to the extent legally permitted, promptly notify the Controller of any request received from a Data Subject and shall not respond except on the documented instructions of the Controller or as required by law.</p>\n<h2>11. Audits</h2>\n<p>The Controller may, on reasonable notice and no more than once per year (save where required by a Supervisory Authority), audit the Processor''s compliance with this DPA, subject to confidentiality obligations.</p>\n<h2>12. Return or Deletion of Personal Data</h2>\n<p>On termination of the Principal Agreement, the Processor shall, at the Controller''s choice, return or delete all Personal Data, save to the extent retention is required by law.</p>\n<h2>13. Liability</h2>\n<p>Each Party''s liability under this DPA is subject to the limitations set out in the Principal Agreement.</p>\n<h2>14. Governing Law</h2>\n<p>This DPA is governed by <strong>{{governing_law}}</strong> with exclusive jurisdiction in <strong>{{jurisdiction}}</strong>.</p>\n<h2>Annex B — Authorised Sub-processors</h2>\n<ul><li>Cloud hosting provider (compute, storage, database).</li><li>Transactional email provider.</li><li>Analytics provider.</li><li>Payment processor.</li></ul>\n<p>The current list is maintained in the Trust Centre on the Platform.</p>';
BEGIN
  UPDATE public.legal_document_templates SET template_content = c_quick,  updated_at = now() WHERE document_code = 'CPA_QUICK';
  UPDATE public.legal_document_templates SET template_content = c_struct, updated_at = now() WHERE document_code = 'CPA_STRUCTURED';
  UPDATE public.legal_document_templates SET template_content = c_ctrl,   updated_at = now() WHERE document_code = 'CPA_CONTROLLED';
  UPDATE public.legal_document_templates SET template_content = c_ra,     updated_at = now() WHERE document_code = 'RA_R2';
  UPDATE public.legal_document_templates SET template_content = c_pp,     updated_at = now() WHERE document_code = 'PRIVACY_POLICY';
  UPDATE public.legal_document_templates SET template_content = c_dpa,    updated_at = now() WHERE document_code = 'DPA';
END $repair$;